document.addEventListener('DOMContentLoaded', () => {
    // --- State Initialization ---
    let exercises = JSON.parse(localStorage.getItem('gt_exercises')) || [];
    let logs = JSON.parse(localStorage.getItem('gt_logs')) || [];

    // --- DOM Elements ---
    const navButtons = document.querySelectorAll('.nav-btn');
    const views = document.querySelectorAll('.view');

    // Workout View Elements
    const workoutExerciseSelect = document.getElementById('workout-exercise-select');
    const setsContainer = document.getElementById('sets-container');
    const btnAddSet = document.getElementById('btn-add-set');
    const btnSaveLog = document.getElementById('btn-save-log');

    // Message Toast
    const saveMsg = document.getElementById('save-msg');

    // Exercise View Elements
    const newExerciseName = document.getElementById('new-exercise-name');
    const btnAddExercise = document.getElementById('btn-add-exercise');
    const exercisesList = document.getElementById('exercises-list');

    // History Elements
    const historyExerciseSelect = document.getElementById('history-exercise-select');
    const historyList = document.getElementById('history-list');

    // Session active sets tracker
    let activeSets = [];

    // --- Navigation ---
    Array.from(navButtons).forEach(btn => {
        btn.addEventListener('click', function (e) {
            e.preventDefault(); // Prevent accidental form submits or webkit defaults

            // Safely remove active classes
            Array.from(navButtons).forEach(b => b.classList.remove('active'));
            Array.from(views).forEach(v => v.classList.remove('active'));

            // Add active class to target
            this.classList.add('active');
            const targetId = this.dataset.target || this.getAttribute('data-target');
            const targetView = document.getElementById(targetId);

            if (targetView) {
                targetView.classList.add('active');
            }

            updateViews();
        });
    });

    // --- Core Functions ---
    function saveState() {
        localStorage.setItem('gt_exercises', JSON.stringify(exercises));
        localStorage.setItem('gt_logs', JSON.stringify(logs));
    }

    function generateId() {
        return Math.random().toString(36).substring(2, 10);
    }

    // --- Sets Tracking UI ---
    function renderSets() {
        setsContainer.innerHTML = '';
        activeSets.forEach((set, idx) => {
            const row = document.createElement('div');
            row.className = 'set-row input-group';
            row.style.marginBottom = '15px';
            row.style.alignItems = 'center';

            row.innerHTML = `
                <div style="width: 30px; font-weight: 700; color: var(--text-muted); font-size: 0.9rem;">${idx + 1}</div>
                <div class="input-field" style="margin-bottom:0">
                    <input type="number" inputmode="decimal" placeholder="Вага" class="clean-input set-weight" value="${set.weight}" style="margin-bottom:0">
                </div>
                <div class="input-field" style="margin-bottom:0">
                    <input type="number" inputmode="numeric" placeholder="Повт." class="clean-input set-reps" value="${set.reps}" style="margin-bottom:0">
                </div>
                <button class="btn-remove-set" style="width:36px; padding: 12px 0; background: transparent; color: var(--danger-color); box-shadow: none; font-size: 1.2rem; cursor: pointer;">✕</button>
            `;
            setsContainer.appendChild(row);

            row.querySelector('.set-weight').addEventListener('input', (e) => activeSets[idx].weight = e.target.value);
            row.querySelector('.set-reps').addEventListener('input', (e) => activeSets[idx].reps = e.target.value);

            row.querySelector('.btn-remove-set').addEventListener('click', () => {
                activeSets.splice(idx, 1);
                if (activeSets.length === 0) {
                    // Prevent deleting the very last entry
                    activeSets.push({ id: generateId(), weight: '', reps: '' });
                }
                renderSets();
            });
        });
    }

    btnAddSet.addEventListener('click', () => {
        // Auto-fill weight from the previous set for convenience
        const lastWeight = activeSets.length > 0 ? activeSets[activeSets.length - 1].weight : '';
        activeSets.push({ id: generateId(), weight: lastWeight, reps: '' });
        renderSets();
    });

    workoutExerciseSelect.addEventListener('change', () => {
        const exId = workoutExerciseSelect.value;
        if (!exId) return;

        // Reset sets for new exercise selection
        activeSets = [];

        // Find last valid log for this exercise to pre-fill weight
        const exLogs = logs.filter(log => log.exerciseId === exId).sort((a, b) => b.timestamp - a.timestamp);
        let defaultWeight = '';
        if (exLogs.length > 0) {
            defaultWeight = exLogs[0].weight; // newest log weight
        }

        activeSets.push({ id: generateId(), weight: defaultWeight, reps: '' });
        renderSets();
    });

    // --- Workout Save ---
    btnSaveLog.addEventListener('click', () => {
        const exId = workoutExerciseSelect.value;
